    27→/** Remove duplicate question text from interviewer messages.
    28→ *  The AI sometimes embeds the question in its reaction AND returns it separately,
    29→ *  causing the backend to concatenate both → question appears twice. */
    30→function deduplicateInterviewerText(text: string): string {
    31→  if (!text) return text
    32→  const idx = text.lastIndexOf('\n\n')
    33→  if (idx === -1) return text
    34→  const before = text.substring(0, idx).trim()
    35→  const after = text.substring(idx + 2).trim()
    36→  if (!after || !before) return text
    37→  const normalize = (s: string) => s.toLowerCase().replace(/[^\w\s]/g, '').replace(/\s+/g, ' ').trim()
    38→  if (normalize(before).includes(normalize(after))) {
    39→    return before
    40→  }
    41→  return text
    42→}
    43→
    44→interface MockInterviewProps {
    45→  mockPastSessions: MockSessionSummary[]
    46→  onSessionComplete: () => void
    47→}
    48→
    49→export function MockInterview({ mockPastSessions, onSessionComplete }: MockInterviewProps) {
    50→  // Mock Interview state
    51→  const [mockTargetRole, setMockTargetRole] = useState('')
    52→  const [mockJobDescription, setMockJobDescription] = useState('')
    53→  const [mockStarting, setMockStarting] = useState(false)
    54→  const [mockSession, setMockSession] = useState<MockSession | null>(null)
    55→  const mockSessionRef = useRef<MockSession | null>(null)
    56→  const [mockResponseText, setMockResponseText] = useState('')
    57→  const [mockSending, setMockSending] = useState(false)
    58→  const [mockEnding, setMockEnding] = useState(false)
    59→  const [mockFeedback, setMockFeedback] = useState<SessionFeedback | null>(null)
    60→  const [mockShowSetup, setMockShowSetup] = useState(false)
    61→  const [viewingHistorySession, setViewingHistorySession] = useState(false)
    62→  const [historyLoading, setHistoryLoading] = useState<number | null>(null)
    63→  const chatEndRef = useRef<HTMLDivElement>(null)
    64→
    65→  // Voice interview state
    66→  const [voiceMode, setVoiceMode] = useState(false)
    67→  const voiceModeRef = useRef(false)
    68→  const [aiSpeaking, setAiSpeaking] = useState(false)
    69→  const [candidateRecording, setCandidateRecording] = useState(false)
    70→  const candidateRecordingRef = useRef(false)
    71→  const [voiceProcessing, setVoiceProcessing] = useState(false)
    72→  const voiceProcessingRef = useRef(false)
    73→  const [silenceTimer, setSilenceTimer] = useState<number>(0)
    74→  const [voiceError, setVoiceError] = useState<string | null>(null)
    75→  const aiAudioRef = useRef<HTMLAudioElement | null>(null)
    76→  const voiceRecorderRef = useRef<MediaRecorder | null>(null)
    77→  const voiceChunksRef = useRef<Blob[]>([])
    78→  const voiceStreamRef = useRef<MediaStream | null>(null)
    79→  const silenceIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
    80→  const analyserRef = useRef<AnalyserNode | null>(null)
    81→  const silenceCountRef = useRef<number>(0)
    82→
    83→  // Mock interview camera state
    84→  const [mockCameraReady, setMockCameraReady] = useState(false)
    85→  const [mockCameraError, setMockCameraError] = useState<string | null>(null)
    86→  const mockVideoRef = useRef<HTMLVideoElement>(null)
    87→  const mockStreamRef = useRef<MediaStream | null>(null)
    88→  const [showTranscript, setShowTranscript] = useState(false)
    89→
    90→  // Enhanced mock interview: AudioContext, frame capture, live transcript
    91→  const audioCtxRef = useRef<AudioContext | null>(null)
    92→  const mockCanvasRef = useRef<HTMLCanvasElement | null>(null)
    93→  const mockFramesRef = useRef<string[]>([])
    94→  const mockPerQuestionFramesRef = useRef<string[]>([])
    95→  const mockQuestionStartTimeRef = useRef<number>(Date.now())
    96→  const mockFrameIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
    97→  const [mockLiveTranscript, setMockLiveTranscript] = useState('')
    98→  const mockLiveTranscriptRef = useRef('')
    99→  const mockRecognitionRef = useRef<any>(null)
   100→  const mockAudioSourceRef = useRef<AudioBufferSourceNode | null>(null)
   101→  const voiceRetryCountRef = useRef<number>(0)
   102→
   103→  // Real-time body language indicators
   104→  const [bodyLanguageIndicators, setBodyLanguageIndicators] = useState<{
   105→    eye_contact: string; posture: string; confidence: string; expression: string; last_updated: string
   106→  } | null>(null)
   107→  const bodyLanguageIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
   108→
   109→  // Feedback expandable sections
   110→  const [expandedSection, setExpandedSection] = useState<string | null>('mock-content')
   111→
   112→  // Keep mockSessionRef in sync
   113→  useEffect(() => { mockSessionRef.current = mockSession }, [mockSession])
   114→
   115→  // Attach camera stream to video element after render
   116→  useEffect(() => {
   117→    if (mockCameraReady && mockStreamRef.current && mockSession && mockSession.status === 'in_progress') {
   118→      const v = mockVideoRef.current
   119→      if (v && !v.srcObject) {
   120→        console.log('[camera] Attaching stream to video element (deferred)')
   121→        v.srcObject = mockStreamRef.current
   122→        v.play().catch(() => { v.play().catch(() => {}) })
   123→      }
   124→    }
   125→  }, [mockCameraReady, mockSession])
   126→
   127→  // When voice mode is enabled and session starts, play first message
   128→  useEffect(() => {
   129→    if (voiceMode && mockSession && mockSession.status === 'in_progress' && mockSession.conversation.length > 0) {
   130→      const lastMsg = mockSession.conversation[mockSession.conversation.length - 1]
   131→      if (lastMsg.role === 'interviewer' && !aiSpeaking && !candidateRecording && !voiceProcessing) {
   132→        if (mockSession.conversation.length === 1) {
   133→          playInterviewerAudio(lastMsg.text)
   134→        }
   135→      }
   136→    }
   137→  }, [voiceMode, mockSession?.id]) // eslint-disable-line react-hooks/exhaustive-deps
   138→
   139→  // Auto-dismiss voice errors after 10 seconds
   140→  useEffect(() => {
   141→    if (voiceError) {
   142→      const t = setTimeout(() => setVoiceError(null), 10000)
   143→      return () => clearTimeout(t)
   144→    }
   145→  }, [voiceError])
   146→
   147→  // Cleanup on unmount
   148→  useEffect(() => {
   149→    return () => {
   150→      stopVoiceMode()
   151→      stopMockCamera()
   152→      stopMockFrameCapture()
   153→      stopMockSpeechRecognition()
   154→      if (audioCtxRef.current && audioCtxRef.current.state !== 'closed') {
   155→        try { audioCtxRef.current.close() } catch (_) {}
   156→      }
   157→    }
   158→  }, [])
   159→
   160→  // ===== CAMERA FUNCTIONS =====
   161→
   162→  async function startMockCamera() {
   163→    try {
   164→      setMockCameraError(null)
   165→      if (!navigator.mediaDevices?.getUserMedia) {
   166→        setMockCameraError('Camera not supported in this browser')
   167→        return
   168→      }
   169→      const constraints = [
   170→        { video: { facingMode: 'user' }, audio: true },
   171→        { video: true, audio: true },
   172→        { video: { facingMode: 'user' }, audio: false },
   173→        { video: true, audio: false },
   174→      ]
   175→      let stream: MediaStream | null = null
   176→      for (const c of constraints) {
   177→        try {
   178→          stream = await navigator.mediaDevices.getUserMedia(c)
   179→          const vt = stream.getVideoTracks()[0]
   180→          if (vt?.readyState === 'live') break
   181→          stream.getTracks().forEach(t => t.stop())
   182→          stream = null
   183→        } catch { stream = null }
   184→      }
   185→      if (!stream) {
   186→        setMockCameraError('Could not access camera')
   187→        return
   188→      }
   189→      mockStreamRef.current = stream
   190→      const v = mockVideoRef.current
   191→      if (v) {
   192→        v.srcObject = stream
   193→        try { await v.play() } catch { try { await v.play() } catch {} }
   194→      }
   195→      setMockCameraReady(true)
   196→    } catch (err: any) {
   197→      setMockCameraError(err.message || 'Camera error')
   198→    }
   199→  }
   200→
   201→  function stopMockCamera() {
   202→    if (mockStreamRef.current) {
   203→      mockStreamRef.current.getTracks().forEach(t => t.stop())
   204→      mockStreamRef.current = null
   205→    }
   206→    setMockCameraReady(false)
   207→  }
   208→
   209→  function captureMockFrame(): string | null {
   210→    if (!mockVideoRef.current) return null
   211→    if (!mockCanvasRef.current) {
   212→      mockCanvasRef.current = document.createElement('canvas')
   213→    }
   214→    const canvas = mockCanvasRef.current
   215→    const video = mockVideoRef.current
   216→    canvas.width = 320
   217→    canvas.height = 240
   218→    const ctx = canvas.getContext('2d')
   219→    if (!ctx) return null
   220→    ctx.drawImage(video, 0, 0, 320, 240)
   221→    return canvas.toDataURL('image/jpeg', 0.7)
   222→  }
   223→
   224→  function startMockFrameCapture() {
   225→    mockFramesRef.current = []
   226→    mockPerQuestionFramesRef.current = []
   227→    mockQuestionStartTimeRef.current = Date.now()
   228→    setTimeout(() => {
   229→      const frame = captureMockFrame()
   230→      if (frame) {
   231→        mockFramesRef.current.push(frame)
   232→        mockPerQuestionFramesRef.current.push(frame)
   233→      }
   234→    }, 500)
   235→    mockFrameIntervalRef.current = setInterval(() => {
   236→      const frame = captureMockFrame()
   237→      if (frame) {
   238→        if (mockFramesRef.current.length < 20) mockFramesRef.current.push(frame)
   239→        if (mockPerQuestionFramesRef.current.length < 8) mockPerQuestionFramesRef.current.push(frame)
   240→      }
   241→    }, 4000)
   242→  }
   243→
   244→  function stopMockFrameCapture() {
   245→    if (mockFrameIntervalRef.current) {
   246→      clearInterval(mockFrameIntervalRef.current)
   247→      mockFrameIntervalRef.current = null
   248→    }
   249→    if (bodyLanguageIntervalRef.current) {
   250→      clearInterval(bodyLanguageIntervalRef.current)
   251→      bodyLanguageIntervalRef.current = null
   252→    }
   253→  }
   254→
   255→  // ===== SPEECH RECOGNITION =====
   256→
   257→  function startMockSpeechRecognition() {
   258→    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition
   259→    if (!SpeechRecognition) return
   260→
   261→    const recognition = new SpeechRecognition()
   262→    recognition.continuous = true
   263→    recognition.interimResults = true
   264→    recognition.lang = 'en-US'
   265→
   266→    let finalTranscript = ''
   267→
   268→    recognition.onresult = (event: any) => {
   269→      let interim = ''
   270→      for (let i = event.resultIndex; i < event.results.length; i++) {
   271→        const result = event.results[i]
   272→        if (result.isFinal) {
   273→          finalTranscript += result[0].transcript + ' '
   274→        } else {
   275→          interim = result[0].transcript
   276→        }
   277→      }
   278→      const combined = finalTranscript + interim
   279→      setMockLiveTranscript(combined)
   280→      mockLiveTranscriptRef.current = combined
   281→    }
   282→
   283→    recognition.onerror = (event: any) => {
   284→      if (event.error === 'no-speech') {
   285→        try { recognition.start() } catch (_) {}
   286→      }
   287→    }
   288→
   289→    recognition.onend = () => {
   290→      if (candidateRecordingRef.current) {
   291→        try { recognition.start() } catch (_) {}
   292→      }
   293→    }
   294→
   295→    try {
   296→      recognition.start()
   297→      mockRecognitionRef.current = recognition
   298→    } catch (_) {}
   299→  }
   300→
   301→  function stopMockSpeechRecognition() {
   302→    if (mockRecognitionRef.current) {
   303→      try { mockRecognitionRef.current.stop() } catch (_) {}
   304→      mockRecognitionRef.current = null
   305→    }
   306→  }
   307→
   308→  function ensureAudioContext(): AudioContext {
   309→    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
   310→      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)()
   311→    }
   312→    if (audioCtxRef.current.state === 'suspended') {
   313→      audioCtxRef.current.resume()
   314→    }
   315→    return audioCtxRef.current
   316→  }
   317→
   318→  // ===== VOICE FUNCTIONS =====
   319→
   320→  function speakWithBrowserTTS(text: string): Promise<void> {
   321→    return new Promise((resolve) => {
   322→      if (!window.speechSynthesis) {
   323→        console.warn('[browser-tts] speechSynthesis not available')
   324→        resolve()
   325→        return
   326→      }
   327→      window.speechSynthesis.cancel()
   328→      const utterance = new SpeechSynthesisUtterance(text)
   329→      utterance.rate = 1.0
   330→      utterance.pitch = 1.0
   331→      utterance.volume = 1.0
   332→
   333→      let voices = window.speechSynthesis.getVoices()
   334→      if (voices.length === 0) {
   335→        window.speechSynthesis.onvoiceschanged = () => {
   336→          voices = window.speechSynthesis.getVoices()
   337→          const preferred = voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female'))
   338→            || voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('samantha'))
   339→            || voices.find(v => v.lang.startsWith('en-US'))
   340→            || voices.find(v => v.lang.startsWith('en'))
   341→          if (preferred) utterance.voice = preferred
   342→        }
   343→      } else {
   344→        const preferred = voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female'))
   345→          || voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('samantha'))
   346→          || voices.find(v => v.lang.startsWith('en-US'))
   347→          || voices.find(v => v.lang.startsWith('en'))
   348→        if (preferred) utterance.voice = preferred
   349→      }
   350→
   351→      const timeout = setTimeout(() => {
   352→        console.warn('[browser-tts] Safety timeout — resolving after 30s')
   353→        resolve()
   354→      }, 30000)
   355→
   356→      const keepAlive = setInterval(() => {
   357→        if (window.speechSynthesis.speaking) {
   358→          window.speechSynthesis.resume()
   359→        } else {
   360→          clearInterval(keepAlive)
   361→        }
   362→      }, 5000)
   363→
   364→      utterance.onend = () => { clearTimeout(timeout); clearInterval(keepAlive); resolve() }
   365→      utterance.onerror = (e) => { clearTimeout(timeout); clearInterval(keepAlive); console.warn('[browser-tts] error:', e); resolve() }
   366→
   367→      window.speechSynthesis.speak(utterance)
   368→      console.log('[browser-tts] Speaking via browser speechSynthesis')
   369→    })
   370→  }
   371→
   372→  async function playInterviewerAudio(text: string) {
   373→    if (!text) return
   374→    setAiSpeaking(true)
   375→    setVoiceError(null)
   376→    try {
   377→      const token = getToken()
   378→      const response = await fetch('/api/interviews/mock/tts', {
   379→        method: 'POST',
   380→        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
   381→        body: JSON.stringify({ text })
   382→      })
   383→
   384→      const contentType = response.headers.get('content-type') || ''
   385→
   386→      if (contentType.includes('application/json')) {
   387→        console.log('[tts-client] TTS API unavailable, falling back to browser speech synthesis')
   388→        await speakWithBrowserTTS(text)
   389→        setAiSpeaking(false)
   390→        if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   391→        return
   392→      }
   393→
   394→      if (!response.ok) {
   395→        console.error('[tts-client] TTS failed:', response.status)
   396→        await speakWithBrowserTTS(text)
   397→        setAiSpeaking(false)
   398→        if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   399→        return
   400→      }
   401→
   402→      const arrayBuffer = await response.arrayBuffer()
   403→      if (arrayBuffer.byteLength < 100) {
   404→        console.error('[tts-client] Audio too small:', arrayBuffer.byteLength)
   405→        await speakWithBrowserTTS(text)
   406→        setAiSpeaking(false)
   407→        if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   408→        return
   409→      }
   410→
   411→      const ctx = ensureAudioContext()
   412→
   413→      try {
   414→        const audioBuffer = await ctx.decodeAudioData(arrayBuffer.slice(0))
   415→        if (mockAudioSourceRef.current) {
   416→          try { mockAudioSourceRef.current.stop() } catch (_) {}
   417→        }
   418→        const source = ctx.createBufferSource()
   419→        source.buffer = audioBuffer
   420→        source.connect(ctx.destination)
   421→        mockAudioSourceRef.current = source
   422→
   423→        source.onended = () => {
   424→          setAiSpeaking(false)
   425→          mockAudioSourceRef.current = null
   426→          if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   427→        }
   428→
   429→        source.start()
   430→        console.log('[tts-client] Playing via Web Audio API')
   431→      } catch (decodeErr) {
   432→        console.warn('[tts-client] Web Audio decode failed, falling back to Audio element:', decodeErr)
   433→        const blob = new Blob([arrayBuffer], { type: 'audio/mpeg' })
   434→        const audioUrl = URL.createObjectURL(blob)
   435→        if (aiAudioRef.current) {
   436→          aiAudioRef.current.pause()
   437→          URL.revokeObjectURL(aiAudioRef.current.src)
   438→        }
   439→        const audio = new Audio(audioUrl)
   440→        aiAudioRef.current = audio
   441→        audio.onended = () => {
   442→          setAiSpeaking(false)
   443→          URL.revokeObjectURL(audioUrl)
   444→          if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   445→        }
   446→        audio.onerror = () => {
   447→          setAiSpeaking(false)
   448→          URL.revokeObjectURL(audioUrl)
   449→          if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 1000)
   450→        }
   451→        await audio.play()
   452→      }
   453→    } catch (err) {
   454→      console.error('[tts-client] TTS playback error:', err)
   455→      try { await speakWithBrowserTTS(text) } catch (_) {}
   456→      setAiSpeaking(false)
   457→      if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   458→    }
   459→  }
   460→
   461→  async function startVoiceRecording() {
   462→    setVoiceError(null)
   463→    setMockLiveTranscript('')
   464→    mockLiveTranscriptRef.current = ''
   465→    try {
   466→      if (!voiceStreamRef.current) {
   467→        if (mockStreamRef.current && mockStreamRef.current.getAudioTracks().length > 0) {
   468→          const audioTrack = mockStreamRef.current.getAudioTracks()[0]
   469→          voiceStreamRef.current = new MediaStream([audioTrack])
   470→        } else {
   471→          voiceStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true })
   472→        }
   473→      }
   474→
   475→      voiceChunksRef.current = []
   476→
   477→      const audioContext = ensureAudioContext()
   478→      const source = audioContext.createMediaStreamSource(voiceStreamRef.current)
   479→      const analyser = audioContext.createAnalyser()
   480→      analyser.fftSize = 512
   481→      source.connect(analyser)
   482→      analyserRef.current = analyser
   483→      silenceCountRef.current = 0
   484→      const recordingStartedAt = Date.now()
   485→
   486→      silenceIntervalRef.current = setInterval(() => {
   487→        if (!analyserRef.current) return
   488→        // Grace period: don't count silence for first 2.5s to let user start speaking
   489→        if (Date.now() - recordingStartedAt < 2500) return
   490→        const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount)
   491→        analyserRef.current.getByteFrequencyData(dataArray)
   492→        const avg = dataArray.reduce((a, b) => a + b, 0) / dataArray.length
   493→        if (avg < 8) {
   494→          silenceCountRef.current++
   495→          setSilenceTimer(Math.round(silenceCountRef.current * 0.2))
   496→          if (silenceCountRef.current >= 25) stopVoiceRecording()
   497→        } else {
   498→          silenceCountRef.current = 0
   499→          setSilenceTimer(0)
   500→        }
   501→      }, 200)
   502→
   503→      const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
   504→        ? 'audio/webm;codecs=opus'
   505→        : MediaRecorder.isTypeSupported('audio/mp4')
   506→          ? 'audio/mp4'
   507→          : 'audio/webm'
   508→
   509→      const recorder = new MediaRecorder(voiceStreamRef.current, { mimeType })
   510→      voiceRecorderRef.current = recorder
   511→
   512→      recorder.ondataavailable = (e) => {
   513→        if (e.data.size > 0) voiceChunksRef.current.push(e.data)
   514→      }
   515→
   516→      recorder.onstop = async () => {
   517→        setCandidateRecording(false)
   518→        candidateRecordingRef.current = false
   519→        if (silenceIntervalRef.current) clearInterval(silenceIntervalRef.current)
   520→        setSilenceTimer(0)
   521→
   522→        if (voiceChunksRef.current.length === 0) return
   523→
   524→        const totalSilenceChecks = silenceCountRef.current
   525→        const currentTranscript = mockLiveTranscriptRef.current
   526→        if (totalSilenceChecks >= 23 && !currentTranscript.trim()) {
   527→          console.log('[voice] Skipping — recording was mostly silence')
   528→          setMockLiveTranscript('')
   529→          setVoiceError('No speech detected. Tap the mic button when ready to speak.')
   530→          return
   531→        }
   532→
   533→        setVoiceProcessing(true)
   534→        voiceProcessingRef.current = true
   535→        try {
   536→          const currentSession = mockSessionRef.current
   537→          if (!currentSession?.id) {
   538→            console.error('[voice] No active session — cannot send voice response')
   539→            setVoiceError('No active interview session. Please restart.')
   540→            setVoiceProcessing(false)
   541→            voiceProcessingRef.current = false
   542→            return
   543→          }
   544→
   545→          const audioBlob = new Blob(voiceChunksRef.current, { type: mimeType })
   546→
   547→          const voicePerQuestionFrames = [...mockPerQuestionFramesRef.current]
   548→          const voiceQuestionDuration = Math.round((Date.now() - mockQuestionStartTimeRef.current) / 1000)
   549→          mockPerQuestionFramesRef.current = []
   550→          mockQuestionStartTimeRef.current = Date.now()
   551→
   552→          const formData = new FormData()
   553→          const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm'
   554→          formData.append('audio', audioBlob, `recording.${ext}`)
   555→          const liveTranscript = mockLiveTranscriptRef.current.trim()
   556→          if (liveTranscript.length >= 5) {
   557→            formData.append('response_text', liveTranscript)
   558→          }
   559→          if (voicePerQuestionFrames.length > 0) {
   560→            formData.append('frames_json', JSON.stringify(voicePerQuestionFrames))
   561→          }
   562→          formData.append('duration_seconds', String(voiceQuestionDuration))
   563→
   564→          let token = getToken()
   565→          const abortController = new AbortController()
   566→          const fetchTimeout = setTimeout(() => abortController.abort(), 28000)
   567→
   568→          let res: Response
   569→          try {
   570→            res = await fetch(`/api/interviews/mock/${currentSession.id}/voice-respond`, {
   571→              method: 'POST',
   572→              headers: { 'Authorization': `Bearer ${token}` },
   573→              body: formData,
   574→              signal: abortController.signal
   575→            })
   576→            // Handle expired token — refresh and retry once
   577→            if (res.status === 401) {
   578→              try {
   579→                const rt = localStorage.getItem('refresh_token')
   580→                if (rt) {
   581→                  const rr = await fetch('/api/auth/refresh', {
   582→                    method: 'POST',
   583→                    headers: { 'Content-Type': 'application/json' },
   584→                    body: JSON.stringify({ refreshToken: rt })
   585→                  })
   586→                  const rd = await rr.json()
   587→                  if (rd.accessToken) {
   588→                    localStorage.setItem('token', rd.accessToken)
   589→                    if (rd.refreshToken) localStorage.setItem('refresh_token', rd.refreshToken)
   590→                    token = rd.accessToken
   591→                    const retryFD = new FormData()
   592→                    retryFD.append('audio', audioBlob, `recording.${ext}`)
   593→                    if (liveTranscript.length >= 5) retryFD.append('response_text', liveTranscript)
   594→                    if (voicePerQuestionFrames.length > 0) retryFD.append('frames_json', JSON.stringify(voicePerQuestionFrames))
   595→                    retryFD.append('duration_seconds', String(voiceQuestionDuration))
   596→                    res = await fetch(`/api/interviews/mock/${currentSession.id}/voice-respond`, {
   597→                      method: 'POST',
   598→                      headers: { 'Authorization': `Bearer ${token}` },
   599→                      body: retryFD,
   600→                      signal: abortController.signal
   601→                    })
   602→                  }
   603→                }
   604→              } catch (refreshErr) { console.warn('[voice] Token refresh failed:', refreshErr) }
   605→            }
   606→          } finally {
   607→            clearTimeout(fetchTimeout)
   608→          }
   609→
   610→          const data = await res.json()
   611→
   612→          if (data.success) {
   613→            voiceRetryCountRef.current = 0
   614→
   615→            const candidateMsg: MockConversationTurn = {
   616→              role: 'candidate',
   617→              text: data.transcribed_text,
   618→              timestamp: new Date().toISOString()
   619→            }
   620→            const cleanedInterviewerMsg = { ...data.interviewer_message, text: deduplicateInterviewerText(data.interviewer_message.text) }
   621→            const textWasDeduped = cleanedInterviewerMsg.text !== data.interviewer_message.text
   622→            setMockSession(prev => prev ? {
   623→              ...prev,
   624→              conversation: [...prev.conversation, candidateMsg, cleanedInterviewerMsg]
   625→            } : null)
   626→            setTimeout(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
   627→
   628→            if (data.interviewer_audio_base64 && !textWasDeduped) {
   629→              setAiSpeaking(true)
   630→              const audioData = Uint8Array.from(atob(data.interviewer_audio_base64), c => c.charCodeAt(0))
   631→              const ctx = ensureAudioContext()
   632→
   633→              try {
   634→                const audioBuffer = await ctx.decodeAudioData(audioData.buffer.slice(0))
   635→                if (mockAudioSourceRef.current) {
   636→                  try { mockAudioSourceRef.current.stop() } catch (_) {}
   637→                }
   638→                const srcNode = ctx.createBufferSource()
   639→                srcNode.buffer = audioBuffer
   640→                srcNode.connect(ctx.destination)
   641→                mockAudioSourceRef.current = srcNode
   642→                srcNode.onended = () => {
   643→                  setAiSpeaking(false)
   644→                  mockAudioSourceRef.current = null
   645→                  if (voiceModeRef.current && !data.is_wrapping_up) startVoiceRecording()
   646→                }
   647→                srcNode.start()
   648→                console.log('[voice-respond] Playing AI audio via Web Audio API')
   649→              } catch (decodeErr) {
   650→                console.warn('[voice-respond] Web Audio decode failed, fallback:', decodeErr)
   651→                const blob = new Blob([audioData], { type: 'audio/mpeg' })
   652→                const url = URL.createObjectURL(blob)
   653→                if (aiAudioRef.current) {
   654→                  aiAudioRef.current.pause()
   655→                  URL.revokeObjectURL(aiAudioRef.current.src)
   656→                }
   657→                const audio = new Audio(url)
   658→                aiAudioRef.current = audio
   659→                audio.onended = () => {
   660→                  setAiSpeaking(false)
   661→                  URL.revokeObjectURL(url)
   662→                  if (voiceModeRef.current && !data.is_wrapping_up) startVoiceRecording()
   663→                }
   664→                audio.onerror = () => {
   665→                  setAiSpeaking(false)
   666→                  URL.revokeObjectURL(url)
   667→                  if (voiceModeRef.current && !data.is_wrapping_up) setTimeout(() => startVoiceRecording(), 1000)
   668→                }
   669→                await audio.play()
   670→              }
   671→            } else {
   672→              // No backend audio or text was deduped (backend audio has question twice) — use frontend TTS
   673→              await playInterviewerAudio(cleanedInterviewerMsg.text)
   674→            }
   675→          } else {
   676→            const errorMsg = data.error || 'Failed to process your response'
   677→            console.warn('[voice] Transcription failed:', errorMsg)
   678→            voiceRetryCountRef.current = 0
   679→            setMockLiveTranscript('')
   680→            if (errorMsg.includes("didn't catch") || errorMsg.includes('Could not transcribe')) {
   681→              setVoiceError('Could not understand your response. Tap the mic button to try again, or type your answer below.')
   682→            } else {
   683→              setVoiceError(errorMsg)
   684→            }
   685→          }
   686→        } catch (err: any) {
   687→          if (err.name === 'AbortError') {
   688→            console.warn('[voice] Request timed out after 28s')
   689→            setVoiceError('The AI is taking too long to respond. Tap the mic to try again, or type your answer below.')
   690→          } else {
   691→            setVoiceError(err.message || 'Voice processing failed. Tap the mic to try again.')
   692→            console.error('Voice response error:', err)
   693→          }
   694→        } finally {
   695→          setVoiceProcessing(false)
   696→          voiceProcessingRef.current = false
   697→        }
   698→      }
   699→
   700→      recorder.start(250)
   701→      setCandidateRecording(true)
   702→      candidateRecordingRef.current = true
   703→
   704→      setMockLiveTranscript('')
   705→      mockLiveTranscriptRef.current = ''
   706→      startMockSpeechRecognition()
   707→    } catch (err: any) {
   708→      console.error('Mic access error:', err)
   709→      setVoiceError('Microphone access denied. Please allow microphone access to use voice mode.')
   710→      setCandidateRecording(false)
   711→      candidateRecordingRef.current = false
   712→    }
   713→  }
