   831→          setMockSession(prev => prev ? {
   832→            ...prev,
   833→            conversation: [...prev.conversation, cleanedResMsg]
   834→          } : null)
   835→          setTimeout(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
   836→          if (cleanedResMsg?.text) {
