   859→  async function endMockInterview() {
   860→    if (!mockSession) return
   861→    setMockEnding(true)
   862→
   863→    if (voiceProcessingRef.current) {
   864→      console.log('[end] Waiting for in-flight voice response to complete...')
   865→      await new Promise<void>(resolve => {
   866→        const check = setInterval(() => {
   867→          if (!voiceProcessingRef.current) { clearInterval(check); resolve() }
   868→        }, 200)
   869→        setTimeout(() => { clearInterval(check); resolve() }, 6000)
   870→      })
   871→    }
   872→
   873→    stopVoiceMode()
   874→    stopMockFrameCapture()
   875→    stopMockSpeechRecognition()
   876→
   877→    const finalFrame = captureMockFrame()
   878→    if (finalFrame && mockFramesRef.current.length < 20) {
   879→      mockFramesRef.current.push(finalFrame)
   880→    }
   881→
   882→    if (voiceMode) {
   883→      const goodbyeText = `Thank you for the interview. I'll prepare your feedback now.`
   884→      Promise.race([
   885→        speakWithBrowserTTS(goodbyeText),
   886→        new Promise(resolve => setTimeout(resolve, 3000))
   887→      ]).catch(() => {})
   888→    }
   889→
   890→    try {
   891→      const frames = mockFramesRef.current.length > 0 ? mockFramesRef.current : undefined
   892→      const res = await apiCall<{ success: boolean; feedback: SessionFeedback; no_feedback?: boolean }>(`/interviews/mock/${mockSession.id}/end`, {
   893→        method: 'POST',
   894→        body: { frames }
   895→      })
   896→      if (res.success) {
