   898→        if (res.no_feedback) {
   899→          setMockFeedback({
   900→            overall_score: 0,
   901→            interview_readiness: 'needs_practice',
   902→            summary: 'Interview ended before any questions were answered. No feedback is available. Start a new interview to practice!',
   903→            strengths: [],
   904→            improvements: ['Complete at least one question to receive feedback'],
