   909→            top_tip: 'Try starting a new interview and answer at least one question to get personalized feedback.'
   910→          } as SessionFeedback)
   911→        } else {
   912→          setMockFeedback(res.feedback)
   913→          if (res.feedback && !res.feedback.presentation) {
   914→            const sessionIdForPolling = mockSession.id
   915→            const pollFeedback = async () => {
   916→              try {
   917→                const pollRes = await apiCall<{ success: boolean; feedback: SessionFeedback }>(`/interviews/mock/sessions/${sessionIdForPolling}/feedback`)
   918→                if (pollRes.success && pollRes.feedback) {
