   939→        interview_readiness: 'needs_practice',
   940→        summary: 'Interview ended. Feedback could not be generated — please try again.',
   941→        strengths: [],
   942→        improvements: [],
   943→        question_scores: [],
   944→        star_method_usage: { score: 0, feedback: 'N/A' },
   945→        communication_quality: { score: 0, feedback: 'N/A' },
   946→        technical_depth: { score: 0, feedback: 'N/A' },
   947→        top_tip: 'Start a new interview to practice.'
   948→      } as SessionFeedback)
   949→      setMockSession(prev => prev ? { ...prev, status: 'completed' } : null)
