      return
    }

    setSubmitting(true)
    const abortController = new AbortController()
    const fetchTimeout = setTimeout(() => abortController.abort(), 35000)
    try {
      const res = await apiCall<{ success: boolean; coaching: TextCoaching }>('/interviews/practice/submit', {
        method: 'POST',
