        alert('Analysis is taking longer than expected. Please try again.')
      } else {
        alert(err.message || 'Failed to get AI coaching. Please try again.')
      }
    } finally {
      clearTimeout(fetchTimeout)
      setSubmitting(false)
    }
  }

