                                setRecordingTime(0)
                              }}
                              className="flex-1"
                            >
                              Re-record
                            </Button>
                            <Button
                              onClick={submitVideoResponse}
                              disabled={transcription.trim().length < 20}
                              className="flex-1"
                            >
                              <Sparkles className="h-4 w-4 mr-1.5" />
