                </Button>
              </div>
            </>
          )}

          {/* ==================== Text Coaching Results ==================== */}
          {practiceQuestion && textCoaching && (
            <>
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  <Trophy className="h-5 w-5 text-primary" />
