                            { key: 'energy', label: 'Energy', icon: Zap },
                            { key: 'articulation', label: 'Articulation', icon: MessageSquare },
                          ].map(item => {
                            const data = ((mockFeedback as any).voice_analysis as any)?.[item.key]
                            if (!data) return null
                            const ItemIcon = item.icon
                            return (
