          </div>

          {/* Overall score */}
          <div className={`text-center p-6 rounded-xl border-2 ${scoreBg(mockFeedback.overall_score)}`}>
            <div className={`text-5xl font-bold ${scoreColor(mockFeedback.overall_score)}`}>
