                {aiSpeaking ? 'Listening to interviewer... mic will auto-activate when they finish' :
                 candidateRecording ? `Speaking... ${silenceTimer > 0 ? `paused ${silenceTimer}s (auto-sends at 5s)` : 'auto-sends when you stop talking'}` :
